reg dout0_q, ce_q;
always @(posedge clk)
    ce_q <= CLOCK_ENABLE;
always @(posedge clk)
    if (CLOCK_ENABLE) dout0_q <= D_OUT_0;
reg dout1_q;
always @(negedge clk)
    if (ce_q) dout1_q <= D_OUT_1;

reg e, clk;
wire q;
// Test 1: enable rises after clock edge
initial begin
    {e, clk} = 2'b00;
    #DELAY; {e, clk} = 2'b00;
    #DELAY; {e, clk} = 2'b01; // clk rises first
    #DELAY; {e, clk} = 2'b11; // then enable
    #DELAY; {e, clk} = 2'b10;
end
// Test 2: enable rises before clock edge
initial begin
    {e, clk} = 2'b00;
    #DELAY; {e, clk} = 2'b10; // enable rises first
    #DELAY; {e, clk} = 2'b11; // then clk
    #DELAY; {e, clk} = 2'b01;
end
